class Solution {
    public int maxSubstrings(String word) {
        int count = 0;
        for (int i = 0; i < word.length() - 3; i++) {
            for (int j = i + 4; j <= word.length(); j++) {
                if (word.charAt(i) == word.charAt(j - 1) && !isIntersecting(word, i, j)) {
                    count++;
                }
            }
        }
        return count;
    }
    private boolean isIntersecting(String word, int start1, int end1) {
        for (int i = 0; i < word.length(); i++) {
            for (int j = i + 4; j <= word.length(); j++) {
                if (word.charAt(i) == word.charAt(j - 1) && (i >= start1 && i <= end1 || j >= start1 && j <= end1)) {
                    return true;
                }
            }
        }
        return false;
    }
}
